class EnvVarCheck
{
    void CheckFlag()
    {
        // .NET 9 breaking change: GetEnvironmentVariable returns null for empty
        // vars on Linux. Use GetEnvironmentVariables() to distinguish "not set"
        // from "explicitly empty".
        var envVars = Environment.GetEnvironmentVariables();
        if (!envVars.Contains("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

