using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now sets the UTF-8 entry-name flag
        // (General Purpose Bit 11). The legacy Java consumer expects Shift-JIS,
        // so we pass that encoding explicitly to suppress the UTF-8 flag.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");

        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: keyed and non-keyed DI registrations are
// now strictly separated. Register as keyed to match the controller's
// [FromKeyedServices("cache")] attribute.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

